def predict(triples: list[Triple]) -> str:
    """Generate a natural language sentence from a list of triples."""
    if not triples:
        return ""

    # Group triples by subject for complex sentence building
    subject_triples = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Mapping predicates to phrase generators with better grammar
    def alt_name(s, o): return f"also known as {o}"
    def creator(s, o): return f"created by {o}"
    def full_name(s, o): return f"whose full name is {o}"
    def founded_by(s, o): return f"founded by {o}"
    def key_person(s, o): return f"{o} is a key person"
    def city(s, o): return f"located in {o}"
    def product(s, o): return f"produces {o}"
    def last_aired(s, o): return f"last aired on {o}"
    def starring(s, o): return f"stars {o}"
    def first_appearance(s, o): return f"first appeared in the film {o}"
    def voice(s, o): return f"voiced by {o}"
    def distributor(s, o): return f"distributed by {o}"
    def birth_place(s, o): return f"born in {o}"
    def award(s, o): return f"received the {o}"
    def broadcasted_by(s, o): return f"broadcasted by {o}"
    def first_aired(s, o): return f"first aired on {o}"
    def series(s, o): return f"part of the series {o}"
    def child(s, o): return f"has a child named {o}"
    def nationality(s, o):
        # Handle nationality more naturally - convert to adjective form
        if o == "Americans":
            return "American"
        elif o == "United States" or o == "USA":
            return "American"
        elif o == "UK" or o == "Britain" or o == "United Kingdom":
            return "British"
        elif o == "France":
            return "French"
        elif o == "Germany":
            return "German"
        elif o == "Japan":
            return "Japanese"
        elif o == "Canada":
            return "Canadian"
        elif o == "Australia":
            return "Australian"
        elif o == "Italy":
            return "Italian"
        elif o == "Spain":
            return "Spanish"
        else:
            return f"from {o}"

    phrase_funcs = {
        "alternativeName": alt_name,
        "creator": creator,
        "fullName": full_name,
        "foundedBy": founded_by,
        "keyPerson": key_person,
        "city": city,
        "product": product,
        "lastAired": last_aired,
        "starring": starring,
        "firstAppearanceInFilm": first_appearance,
        "voice": voice,
        "distributor": distributor,
        "birthPlace": birth_place,
        "nationality": nationality,
        "award": award,
        "broadcastedBy": broadcasted_by,
        "firstAired": first_aired,
        "series": series,
        "child": child,
    }

    # Group creators together for better sentence flow
    creator_values = []
    other_triples = []

    for t in triples:
        if t.predicate == "creator":
            creator_values.append(t.object)
        else:
            other_triples.append(t)

    # Build phrases for non-creator triples
    other_phrases = []
    for t in other_triples:
        func = phrase_funcs.get(t.predicate)
        if func:
            if t.predicate == "nationality":
                other_phrases.append(f"is {func(t.subject, t.object)}")
            else:
                other_phrases.append(func(t.subject, t.object))

    # Combine creator information
    if creator_values:
        if len(creator_values) == 1:
            creator_phrase = f"created by {creator_values[0]}"
        else:
            creator_phrase = f"created by {', '.join(creator_values[:-1])} and {creator_values[-1]}"
    else:
        creator_phrase = None

    if not creator_phrase and not other_phrases:
        return ""

    # Build the main sentence
    subject = triples[0].subject

    all_parts = []
    if creator_phrase:
        all_parts.append(creator_phrase)
    all_parts.extend(other_phrases)

    if len(all_parts) == 1:
        return f"{subject} {all_parts[0]}."
    elif len(all_parts) == 2:
        return f"{subject} {all_parts[0]} and {all_parts[1]}."
    else:
        # Multiple parts - use commas and 'and' before last
        middle = ", ".join(all_parts[:-1])
        last = all_parts[-1]
        return f"{subject} {middle}, and {last}."

